// UserAPIServer is the server API for UserAPI service.
// All implementations must embed UnimplementedUserAPIServer
// for forward compatibility.
type UserAPIServer interface {
	ListNodes(context.Context, *ListNodesRequest) (*ListNodesResponse, error)
	ListServices(context.Context, *ListServicesRequest) (*ListServicesResponse, error)
	CreateSession(context.Context, *CreateSessionRequest) (*CreateSessionResponse, error)
	ListSessions(context.Context, *ListSessionsRequest) (*ListSessionsResponse, error)
	WhoAmI(context.Context, *Empty) (*WhoAmIResponse, error)
	// SessionSignal is the ephemeral client's session p2p ICE signaling channel,
	// bidi-streamed and mTLS-bound to a just-issued session_id. The controller is a
	// stateless forwarder between this stream and the agent's NodeControl stream
	// (keyed by session_id) — never the wgpub/overlay disco path.
	SessionSignal(grpc.BidiStreamingServer[ClientSignal, ControllerSignal]) error
	// SessionControl is the client's belt-and-suspenders enforcement channel for a
	// DIRECT p2p session: the client streams keepalives and the controller pushes the
	// same signed revoke / lease-expiry it pushes to the agent, so EITHER honest
	// end closes the conduit even if the other (e.g. a compromised agent) ignores
	// the cut. The agent remains the primary gate; this is a bounded residual.
	SessionControl(grpc.BidiStreamingServer[ClientControl, ControllerEnforcement]) error
	// Heartbeat re-asserts continuous PRESENCE for a presence-required session: the
	// client proves a human factor (software stub now, WebAuthn/FIDO2 later) every
	// heartbeat_interval; the controller stamps last-presence and rotates the single-use
	// challenge. When beats stop, presence goes stale and the continuous sweep drops
	// the session (the fail-closed lease is the actual kill).
	Heartbeat(context.Context, *HeartbeatRequest) (*HeartbeatResponse, error)
	// (DNS is no longer a controller RPC: in-network DNS is resolved LOCALLY at each
	// agent from the zone PUSHED in NetworkSpec.dns_records — no per-query controller
	// dependency. See NetworkSpec.dns_zone / memory geneza-roadmap-dns-tenancy.)
	// ListRecordings returns the recording index rows for the workspace. GetRecording
	// streams the opaque CIPHERTEXT blob plus its node-signed manifest; the controller
	// never decrypts — the auditor supplies the workspace audit key. Both require the
	// audit/replay capability, and GetRecording emits a per-fetch audit event.
	ListRecordings(context.Context, *ListRecordingsRequest) (*ListRecordingsResponse, error)
	GetRecording(*GetRecordingRequest, grpc.ServerStreamingServer[RecordingBlobChunk]) error
	// Vulnerability query surface (workspace-scoped, read-only). ListNodeCVEs is the
	// "what CVEs affect node N?" view; ListNodesAffectedByCVE is the inverse "what
	// nodes does CVE-X affect?" fleet view; ListNodeComponents returns a node's
	// resolved software inventory. The workspace is taken from the caller's cert, so
	// no request carries a workspace and one tenant's exploitable surface stays
	// invisible to another. All three need at least workspace-member standing.
	ListNodeCVEs(context.Context, *ListNodeCVEsRequest) (*ListNodeCVEsResponse, error)
	ListNodesAffectedByCVE(context.Context, *ListNodesAffectedByCVERequest) (*ListNodesAffectedByCVEResponse, error)
	ListNodeComponents(context.Context, *ListNodeComponentsRequest) (*ListNodeComponentsResponse, error)
	// ListWorkspaceCVEs is the fleet-wide rollup: every CVE affecting any node in the
	// caller's workspace, with the representative severity/status, the count and list
	// of distinct affected nodes (host and container-image verdicts unioned), and a
	// fixing version. Same cert-scoped tenancy and ws-member gate as the others.
	ListWorkspaceCVEs(context.Context, *ListWorkspaceCVEsRequest) (*ListWorkspaceCVEsResponse, error)
	mustEmbedUnimplementedUserAPIServer()
}

